parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

// Validate required fields
if (!body.email || !body.first_name) {
  return [{ json: { valid: false, error: 'Email and first name are required' } }];
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  return [{ json: { valid: false, error: 'Invalid email format' } }];
}

// Validate phone (South African numbers)
const phoneRaw = (body.phone || '').replace(/\s+/g, '');
const saPhoneRegex = /^(\+27|0)[6-8][0-9]{8}$/;
const phoneValid = !phoneRaw || saPhoneRegex.test(phoneRaw);

// Build lead score based on completeness and intent signals
let leadScore = 0;
if (body.budget && body.budget > 0) leadScore += 20;
if (body.bedrooms) leadScore += 10;
if (body.province) leadScore += 10;
if (body.timeline && body.timeline !== 'just_browsing') leadScore += 15;
if (body.financing_type === 'cash') leadScore += 25;
if (body.financing_type === 'bond_approved') leadScore += 20;
if (phoneRaw && phoneValid) leadScore += 10;
if (body.viewing_requested) leadScore += 15;
if (body.property_id) leadScore += 20;

const lead = {
  valid: true,
  first_name: String(body.first_name || '').substring(0, 50).trim(),
  last_name: String(body.last_name || '').substring(0, 50).trim(),
  email: body.email.toLowerCase().trim(),
  phone: phoneValid ? phoneRaw : '',
  message: String(body.message || '').substring(0, 2000).trim(),
  property_id: body.property_id || null,
  property_url: body.property_url || '',
  property_title: body.property_title || '',
  budget: parseFloat(body.budget) || 0,
  bedrooms: parseInt(body.bedrooms) || 0,
  province: body.province || '',
  city: body.city || '',
  property_type: body.property_type || '',
  timeline: body.timeline || 'unknown',
  financing_type: body.financing_type || 'unknown',
  viewing_requested: body.viewing_requested || false,
  lead_score: Math.min(leadScore, 100),
  source: body.source || body.utm_source || 'website',
  utm_medium: body.utm_medium || '',
  utm_campaign: body.utm_campaign || '',
  ip_address: $input.first().json.headers?.['x-forwarded-for'] || '',
  user_agent: $input.first().json.headers?.['user-agent'] || '',
  submitted_at: new Date().toISOString(),
  status: 'new'
};

return [{ json: lead }];

